}
function MatchSignalForProject($project,$signals){
$name=$project.Name
$path=$project.FullName
foreach($s in @($signals.heartbeat,$signals.project_signal)){if($null -eq $s){continue};$sid=[string]$s.project_id;$spath=[string]$s.project_path;if($sid -and ($name -eq $sid -or $name -like ("*"+$sid+"*") -or $sid -like ("*"+$name+"*"))){return $s};if($spath -and $path -eq $spath){return $s}}
return $null
}
function ApplySignal($sig,$tmp){
if($null -eq $sig){return $tmp}
if($sig.PSObject.Properties.Name -contains "phase" -and $sig.phase){$tmp.phase=[string]$sig.phase}
if($sig.PSObject.Properties.Name -contains "progress_pct" -and $null -ne $sig.progress_pct){$tmp.score=[int]$sig.progress_pct}
if($sig.PSObject.Properties.Name -contains "state" -and $sig.state){$tmp.worker=[string]$sig.state}
if($sig.PSObject.Properties.Name -contains "next_action" -and $sig.next_action){$tmp.next=[string]$sig.next_action}
if($sig.PSObject.Properties.Name -contains "blocked_reason" -and $sig.blocked_reason){$tmp.block="BLOCK";$tmp.cause=[string]$sig.blocked_reason}
$tmp.signal_source="heartbeat"
return $tmp
}
