function UXOk([string]$m){UX ("[OK] "+$m) "ok"}
function UXWarn([string]$m){UX ("[WARN] "+$m) "warn"}
function P(){Write-Host "";Read-Host "[Enter] volver / refrescar"|Out-Null}
function Short([string]$s,[int]$n){if($null -eq $s){return ""};if($s.Length -le $n){return $s};return $s.Substring(0,$n-3)+"..."}
function Bar([int]$pct,[string]$state=""){if($pct -lt 0){$pct=0};if($pct -gt 100){$pct=100};$w=10;$f=[math]::Floor($pct/10);if($state -eq "RUNNING" -and $f -lt 10){return "["+("#"*$f)+">"+("-"*([math]::Max(0,$w-$f-1)))+"]"};if($state -eq "BLOCKED"){return "[!!!!------]"};if($state -eq "DONE"){return "[##########]"};return "["+("#"*$f)+("-"*($w-$f))+"]"}
function Header([string]$section=""){Clear-Host;UX "==== PROYECTOS / CENTRO DE PROYECTOS ====" "title";UX "Ruta: INICIO > Proyectos" "route";UX "Rol: entrada humana principal para ver cartera, workers y bloqueos" "role";UX "Principio: tabla operativa con progreso visual y senales de worker" "principle";if($section){UX $section "section"};Write-Host ""}
function EnsureRoots(){foreach($r in $ProjectRoots){if($r -like (Join-Path $Core "projects")){New-Item -ItemType Directory -Force -Path $r|Out-Null}}}
function GetProjects(){EnsureRoots;$all=@();foreach($r in $ProjectRoots){if(Test-Path $r){$all+=Get-ChildItem $r -Directory -ErrorAction SilentlyContinue|Where-Object{$_.Name -match "^ENGREMIAT_PROJECT_" -or (Test-Path (Join-Path $_.FullName "MODULOS")) -or (Test-Path (Join-Path $_.FullName "project.json"))}}};$all|Sort-Object LastWriteTime -Descending -Unique}
function CountFiles([string]$p,[string]$filter="*"){if(Test-Path $p){return @((Get-ChildItem $p -File -Recurse -Filter $filter -ErrorAction SilentlyContinue)|Select-Object -First 500).Count};return 0}
function CountDirs([string]$p){if(Test-Path $p){return @((Get-ChildItem $p -Directory -ErrorAction SilentlyContinue)).Count};return 0}
function ReadJsonSafe([string]$p){try{if(Test-Path $p){return Get-Content $p -Raw|ConvertFrom-Json}}catch{};return $null}
function GetLocalSignals(){
$hb=ReadJsonSafe (Join-Path $Core "documents\worker-sync\worker-heartbeat-latest.json")
$ps=ReadJsonSafe (Join-Path $Core "documents\worker-sync\project-signal-latest.json")
return [pscustomobject]@{heartbeat=$hb;project_signal=$ps}
}
function MatchSignalForProject($project,$signals){
$name=$project.Name
$path=$project.FullName
foreach($s in @($signals.heartbeat,$signals.project_signal)){if($null -eq $s){continue};$sid=[string]$s.project_id;$spath=[string]$s.project_path;if($sid -and ($name -eq $sid -or $name -like ("*"+$sid+"*") -or $sid -like ("*"+$name+"*"))){return $s};if($spath -and $path -eq $spath){return $s}}
return $null
}
function ApplySignal($sig,$tmp){
if($null -eq $sig){return $tmp}
if($sig.PSObject.Properties.Name -contains "phase" -and $sig.phase){$tmp.phase=[string]$sig.phase}
if($sig.PSObject.Properties.Name -contains "progress_pct" -and $null -ne $sig.progress_pct){$tmp.score=[int]$sig.progress_pct}
if($sig.PSObject.Properties.Name -contains "state" -and $sig.state){$tmp.worker=[string]$sig.state}
if($sig.PSObject.Properties.Name -contains "next_action" -and $sig.next_action){$tmp.next=[string]$sig.next_action}
if($sig.PSObject.Properties.Name -contains "blocked_reason" -and $sig.blocked_reason){$tmp.block="BLOCK";$tmp.cause=[string]$sig.blocked_reason}
$tmp.signal_source="heartbeat"
return $tmp
}
function DetectPhase($s){if($s.block -eq "BLOCK"){return "BLOQUEO"};if($s.reports -gt 0 -and $s.mods -gt 0){return "VALIDAR"};if($s.mods -gt 3){return "MODULOS"};if($s.mods -gt 0){return "INICIO"};return "BASE"}
function DetectWorker($dir,$block,$ageHours){$lock=@(Get-ChildItem $dir -Recurse -File -Include "*.lock","worker.lock",".worker-running" -ErrorAction SilentlyContinue|Select-Object -First 1);if($lock.Count){return "RUNNING"};$err=@(Get-ChildItem $dir -Recurse -File -Include "*error*.json","*fail*.json","*.err" -ErrorAction SilentlyContinue|Select-Object -First 1);if($err.Count){return "ERROR"};if($block -eq "BLOCK"){return "BLOCKED"};if($ageHours -le 1){return "RUNNING"};if($ageHours -le 24){return "IDLE"};return "WAITING"}
function NextAction($s){if($s.block -eq "BLOCK"){return "reparar estructura"};if($s.reports -eq 0){return "generar evidencia"};if($s.mods -lt 2){return "ampliar modulos"};if($s.worker -eq "WAITING"){return "reactivar worker"};return "validar siguiente"}
