function ProjectModules(){Header "MODULOS DEL PROYECTO";$projects=@(GetProjects);if(!$projects.Count){UXWarn "No hay proyectos detectados.";P;return};$localSignals=GetLocalSignals;$i=1;foreach($p in $projects){$s=ProjectSignal $p $localSignals;UX ("["+($i)+"] "+$p.Name+"  mods="+$s.mods+"  "+$s.block+"  "+$s.next);$i++};Write-Host "";UX "[b] volver" "muted";$op=Read-Host "PROYECTO_MODULOS";if($op -eq "b"){return};$n=0;if(![int]::TryParse($op,[ref]$n) -or $n -lt 1 -or $n -gt $projects.Count){UXWarn "Seleccion no valida";Start-Sleep -Milliseconds 700;return};$mod=Join-Path $projects[$n-1].FullName "MODULOS";New-Item -ItemType Directory -Force -Path $mod|Out-Null;$mods=@(Get-ChildItem $mod -Directory -ErrorAction SilentlyContinue|Sort-Object Name);Header ("MODULOS / "+$projects[$n-1].Name);if(!$mods.Count){UXWarn "Sin modulos todavia.";UX ("Carpeta: "+$mod) "muted"}else{$j=1;foreach($m in $mods){UX ("["+($j)+"] "+$m.Name);$j++}};Write-Host "";UX "[o] abrir carpeta modulos | [Enter] volver" "muted";$x=Read-Host "MODULOS";if($x -eq "o"){Start-Process explorer.exe $mod}}
